/**
 * @file fft_radix3_avx512_ct_t1_dit_log3.h
 * @brief DFT-3 AVX512 t1 DIT log3 (in-place, derived twiddles)
 *
 * FFTW-style codelet for recursive CT executor.
 * Generated by gen_radix3.py --variant ct_t1_dit_log3
 */

#ifndef FFT_RADIX3_AVX512_CT_CT_T1_DIT_LOG3_H
#define FFT_RADIX3_AVX512_CT_CT_T1_DIT_LOG3_H

#include <immintrin.h>

#ifndef R3L_CT_LD
#define R3L_CT_LD(p) _mm512_loadu_pd(p)
#define R3L_CT_ST(p,v) _mm512_storeu_pd((p),(v))
#endif
#define LD R3L_CT_LD
#define ST R3L_CT_ST

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix3_t1_dit_log3_fwd_avx512(
    double * __restrict__ rio_re, double * __restrict__ rio_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t ios, size_t me)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS    = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t m = 0; m < me; m += 8) {
        /* Load base twiddle w1, derive w2 (1 cmul) */
        const __m512d w1r = LD(&W_re[0*me+m]), w1i = LD(&W_im[0*me+m]);
        __m512d w2r, w2i;
        w2r = _mm512_fmsub_pd(w1r,w1r,_mm512_mul_pd(w1i,w1i));
        w2i = _mm512_fmadd_pd(w1r,w1i,_mm512_mul_pd(w1i,w1r));

        x0_re = LD(&rio_re[m+0*ios]);
        x0_im = LD(&rio_im[m+0*ios]);
        x1_re = LD(&rio_re[m+1*ios]);
        x1_im = LD(&rio_im[m+1*ios]);
        x2_re = LD(&rio_re[m+2*ios]);
        x2_im = LD(&rio_im[m+2*ios]);
        { __m512d tr = x1_re;
          x1_re = _mm512_fmsub_pd(x1_re,w1r,_mm512_mul_pd(x1_im,w1i));
          x1_im = _mm512_fmadd_pd(tr,w1i,_mm512_mul_pd(x1_im,w1r)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmsub_pd(x2_re,w2r,_mm512_mul_pd(x2_im,w2i));
          x2_im = _mm512_fmadd_pd(tr,w2i,_mm512_mul_pd(x2_im,w2r)); }

        /* DFT-3 butterfly [fwd] */
        __m512d ar=_mm512_add_pd(x1_re,x2_re), ai=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm512_add_pd(x0_re,ar); x0_im=_mm512_add_pd(x0_im,ai);
        x1_re=_mm512_fmadd_pd(KS,di,R1r); x1_im=_mm512_fnmadd_pd(KS,dr,R1i);
        x2_re=_mm512_fnmadd_pd(KS,di,R1r); x2_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], x0_re);
        ST(&rio_im[m+0*ios], x0_im);
        ST(&rio_re[m+1*ios], x1_re);
        ST(&rio_im[m+1*ios], x1_im);
        ST(&rio_re[m+2*ios], x2_re);
        ST(&rio_im[m+2*ios], x2_im);
    }
}

static __attribute__((target("avx512f,avx512dq,fma"))) void
radix3_t1_dit_log3_bwd_avx512(
    double * __restrict__ rio_re, double * __restrict__ rio_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t ios, size_t me)
{
    const __m512d sign_flip = _mm512_set1_pd(-0.0);
    const __m512d KHALF = _mm512_set1_pd(0.500000000000000000000000000000000000000000000);
    const __m512d KS    = _mm512_set1_pd(0.866025403784438596588302061718422919511795044);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m512d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im;

    for (size_t m = 0; m < me; m += 8) {
        /* Load base twiddle w1, derive w2 (1 cmul) */
        const __m512d w1r = LD(&W_re[0*me+m]), w1i = LD(&W_im[0*me+m]);
        __m512d w2r, w2i;
        w2r = _mm512_fmsub_pd(w1r,w1r,_mm512_mul_pd(w1i,w1i));
        w2i = _mm512_fmadd_pd(w1r,w1i,_mm512_mul_pd(w1i,w1r));

        x0_re = LD(&rio_re[m+0*ios]);
        x0_im = LD(&rio_im[m+0*ios]);
        x1_re = LD(&rio_re[m+1*ios]);
        x1_im = LD(&rio_im[m+1*ios]);
        x2_re = LD(&rio_re[m+2*ios]);
        x2_im = LD(&rio_im[m+2*ios]);
        { __m512d tr = x1_re;
          x1_re = _mm512_fmadd_pd(x1_re,w1r,_mm512_mul_pd(x1_im,w1i));
          x1_im = _mm512_fmsub_pd(x1_im,w1r,_mm512_mul_pd(tr,w1i)); }
        { __m512d tr = x2_re;
          x2_re = _mm512_fmadd_pd(x2_re,w2r,_mm512_mul_pd(x2_im,w2i));
          x2_im = _mm512_fmsub_pd(x2_im,w2r,_mm512_mul_pd(tr,w2i)); }

        /* DFT-3 butterfly [bwd] */
        __m512d ar=_mm512_add_pd(x1_re,x2_re), ai=_mm512_add_pd(x1_im,x2_im);
        __m512d dr=_mm512_sub_pd(x1_re,x2_re), di=_mm512_sub_pd(x1_im,x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,x0_im);
        x0_re=_mm512_add_pd(x0_re,ar); x0_im=_mm512_add_pd(x0_im,ai);
        x2_re=_mm512_fmadd_pd(KS,di,R1r); x2_im=_mm512_fnmadd_pd(KS,dr,R1i);
        x1_re=_mm512_fnmadd_pd(KS,di,R1r); x1_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], x0_re);
        ST(&rio_im[m+0*ios], x0_im);
        ST(&rio_re[m+1*ios], x1_re);
        ST(&rio_im[m+1*ios], x1_im);
        ST(&rio_re[m+2*ios], x2_re);
        ST(&rio_im[m+2*ios], x2_im);
    }
}


#undef LD
#undef ST

#endif /* FFT_RADIX3_AVX512_CT_CT_T1_DIT_LOG3_H */
